def set_individual_id(apps, schema_editor):
    Sample = apps.get_model('seqr', 'Sample')
    Individual = apps.get_model('seqr', 'Individual')

    db_alias = schema_editor.connection.alias

    mismatch_samples = Sample.objects.using(db_alias).filter(is_active=True).exclude(sample_id=models.F('individual__individual_id'))
    individual_ids = []
    for sample in mismatch_samples:
        individual = sample.individual
        individual.display_name = individual.individual_id
        # Since some of these are sample swamps, set a padded id to avoid conflicts and then trim whitespace for clean up
        individual.individual_id = f' {sample.sample_id} '
        individual.save()
        individual_ids.append(individual.id)

    updated = Individual.objects.using(db_alias).filter(id__in=individual_ids).update(individual_id=Trim('individual_id'))
    if updated:
        print(f'Updated individual_id for {updated} individuals to match their active sample_id')


def populate_datasets(apps, schema_editor):
    Dataset = apps.get_model('seqr', 'Dataset')
    Sample = apps.get_model('seqr', 'Sample')
    db_alias = schema_editor.connection.alias

    dataset_aggs = Sample.objects.using(db_alias).values(
        'sample_type', 'dataset_type', project=models.F('individual__family__project'), group_loaded_date=TruncDate('loaded_date'),
    ).annotate(
        guid=models.Max('guid'),
        loaded_date=models.Max('loaded_date'),
        created_date=models.Max('created_date'),
        last_modified_date=models.Max('last_modified_date'),
        created_by_id=models.Min('created_by_id'),
        data_sources=ArrayAgg('data_source', distinct=True, filter=models.Q(data_source__isnull=False)),
        es_indices=ArrayAgg('elasticsearch_index', distinct=True, filter=models.Q(elasticsearch_index__isnull=False)),
        active_individuals=ArrayAgg('individual__id', distinct=True, filter=models.Q(is_active=True)),
        inactive_individuals=ArrayAgg('individual__id', distinct=True, filter=models.Q(is_active=False)),
    )

    datasets = []
    active_individuals = []
    inactive_individuals = []
    for dataset_agg in dataset_aggs:
        del dataset_agg['project']
        del dataset_agg['group_loaded_date']
        active_individuals.append(dataset_agg.pop('active_individuals'))
        inactive_individuals.append(dataset_agg.pop('inactive_individuals'))
        data_sources = dataset_agg.pop('data_sources')
        es_indices = dataset_agg.pop('es_indices')
        datasets.append(Dataset(**dataset_agg, data_source=','.join(data_sources or es_indices)))

    created = Dataset.objects.using(db_alias).bulk_create(datasets)
    if created:
        print(f'Created {len(created)} datasets.')

    ActiveRelation = Dataset.active_individuals.through
    InactiveRelation = Dataset.inactive_individuals.through

    active_relations = []
    for dataset, individual_ids in zip(created, active_individuals):
        active_relations.extend(ActiveRelation(dataset_id=dataset.id, individual_id=ind_id) for ind_id in individual_ids)
    ActiveRelation.objects.using(db_alias).bulk_create(active_relations)
    if active_relations:
        print(f'Created {len(active_relations)} active samples relations')

    inactive_relations = []
    for dataset, individual_ids in zip(created, inactive_individuals):
        inactive_relations.extend(InactiveRelation(dataset_id=dataset.id, individual_id=ind_id) for ind_id in individual_ids)
    InactiveRelation.objects.using(db_alias).bulk_create(inactive_relations)
    if inactive_relations:
        print(f'Created {len(inactive_relations)} inactive samples relations')


